import { useEffect, useState } from "react";

export default function PageHeader() {
  const [timestamp, setTimestamp] = useState(null);

  useEffect(() => {
    setTimestamp(Date.now());
  }, []);

  return (
    <header>
      <h1>Jupyter Arena</h1>
      {timestamp && (
        <p className="subtitle">Session started: {new Date(timestamp).toLocaleTimeString()}</p>
      )}
    </header>
  );
}

import { useRef } from "react";

export default function PageHeader() {
  const timestampRef = useRef(Date.now());

  return (
    <header>
      <h1>Jupyter Arena</h1>
      <p className="subtitle">Session started: {new Date(timestampRef.current).toLocaleTimeString()}</p>
    </header>
  );
}

